import React from 'react';
import { useSelector } from 'react-redux';

import NavigationItem from './NavigationItem/NavigationItem';
import LogoContainer from '../LogoContainer/LogoContainer';

import styles from './NavigationItems.module.css';

const NavigationItems = props => {
    const homeRef = useSelector(state => state.scroll.homeRef);
    const aboutRef = useSelector(state => state.scroll.aboutRef);
    const servicesRef = useSelector(state => state.scroll.servicesRef);
    const projectsRef = useSelector(state => state.scroll.projectsRef);
    const contactRef = useSelector(state => state.scroll.contactRef);

  const navHeaders = [
    'Home',
    'About',
    'Services',
    'Projects',
    // 'Blog',
    'Contact',
  ];

  const navigationHeaders = navHeaders.map (header => {
    switch (header) {
      case 'Home':
        return <NavigationItem key={header} navRef={homeRef} >{header}</NavigationItem>;
      case 'About':
        return <NavigationItem key={header} navRef={aboutRef} >{header}</NavigationItem>;
      case 'Services':
        return <NavigationItem key={header} navRef={servicesRef} >{header}</NavigationItem>;
      case 'Projects':
        return <NavigationItem key={header} navRef={projectsRef} >{header}</NavigationItem>;
      case 'Blog':
        return <NavigationItem key={header} blog >{header}</NavigationItem>;
      case 'Contact':
        return <NavigationItem key={header} navRef={contactRef} >{header}</NavigationItem>;
      default:
        return '';
    }
  });

  let navigationItems = (
    <div className={styles.NavBarContainer}>
      <LogoContainer rowNav />
      <ul className={styles.NavigationItems}>
        {navigationHeaders}
      </ul>
    </div>
  );

  if (props.mobil) {
    navigationItems = (
      <div className={styles.NavBarContainerMobil}>
        <ul className={styles.NavigationItemsMobil}>
          {navigationHeaders}
        </ul>
      </div>
    );
  }

  return navigationItems;
};

export default NavigationItems;
