/* eslint-disable jsx-a11y/anchor-is-valid */
import React from 'react';

import styles from './NavigationItem.module.css';

const scrollToRef = (ref) => window.scrollTo(0, ref.current.offsetTop - 150)

const NavigationItem = props => {


  const executeScroll = () => scrollToRef(props.navRef);

  let navItem =  <li className={styles.LinkContainer}>
  <a
    onClick={executeScroll}
    className={styles.Link}
    style={{backgroundColor: props.colorBg}}
  >
    {props.children}
  </a>
</li>;

if(props.blog) {
  navItem =  <li className={styles.LinkContainer}>
  <a
    onClick={executeScroll}
    className={styles.LinkBlog}
    style={{backgroundColor: props.colorBg}}
  >
    {props.children}
  </a>
</li>;
}

  return navItem;
};

export default NavigationItem;
